import json

def analyze_driving_scenario(scenario):
    # Define traffic rules and common practices
    traffic_rules = {
        "Wrong Way Sign": "This sign indicates that traffic should not proceed in the given direction on the road."
    }

    # Determine the road type
    if scenario['road_type'] == 'Two-Way Street':
        # Two-way streets typically support bidirectional traffic
        expected_traffic_direction = 'Bidirectional'
    else:
        # Other road types may have different traffic directions
        expected_traffic_direction = 'Unspecified'

    # Check for inconsistencies in the traffic signs
    for sign in scenario['traffic_signs']:
        if sign in traffic_rules and traffic_rules[sign]!= 'Bidirectional':
            # If the sign indicates wrong way traffic, but the road supports bidirectional traffic, there is an inconsistency
            inconsistency = True
            reason = f"The '{sign}' sign indicates wrong way traffic, but the road supports {expected_traffic_direction} traffic."
            return {
                "Inconsistency Detected": "Yes",
                "Reasoning": reason
            }
        elif sign in traffic_rules and traffic_rules[sign] == 'Bidirectional':
            # If the sign indicates bidirectional traffic, but the road supports unspecified traffic, there is an inconsistency
            inconsistency = True
            reason = f"The '{sign}' sign indicates bidirectional traffic, but the road supports {expected_traffic_direction} traffic."
            return {
                "Inconsistency Detected": "Yes",
                "Reasoning": reason
            }

    # If no inconsistencies are found, return 'No'
    return {
        "Inconsistency Detected": "No",
        "Reasoning": "No inconsistencies found in the traffic signs."
    }

